type SelectProps = {
  label?: string
  options: any[]
  value?: any
  onChange?: (data: any) => void
} & DetailedHTMLProps<SelectHTMLAttributes<HTMLSelectElement>, HTMLSelectElement>

export const Select = ({
  label = '',
  value = '',
  options = [],
  onChange,
  id,
  ...otherProps
}: SelectProps) => (
  <Container>
    <select
      id={id}
      value={value}
