import { useState, ChangeEvent } from 'react'
import { useNavigate } from 'react-router-dom'

import { saveOrderAction } from '../../../../app-state/order'
import { useAppDispatch, useAppSelector } from '../../../../app-state'
import { clearCartAction, selectCartItems } from '../../../../app-state/cart'
import { Button } from '../../../../components/Button'
import { Input } from '../../../../components/forms/Input'
import { type DeliveryDetailsFormData } from './validation'

type DeliveryDetailsProps = {
  formData: DeliveryDetailsFormData
  setFormData: (data: Partial<DeliveryDetailsFormData>) => void
  onPrevious: () => void
}

type FormErrors = {
  [K in keyof DeliveryDetailsFormData]?: string
}

const deliveryFields: (keyof DeliveryDetailsFormData)[] = ['address', 'city', 'postcode']

export const DeliveryDetails = ({ formData, setFormData, onPrevious }: DeliveryDetailsProps) => {
  const navigate = useNavigate()
  const dispatch = useAppDispatch()
  const cartItems = useAppSelector(selectCartItems)
  const [errors, setErrors] = useState<FormErrors>({})
  const [form, setForm] = useState<DeliveryDetailsFormData>(formData)
  const [isSubmitted, setIsSubmitted] = useState(false)

  const validateField = (
    name: keyof DeliveryDetailsFormData,
    value: string
  ): string | undefined => {
    if (!value) return 'Required'

    switch (name) {
      case 'address': {
        return value.length < 5 ? 'Please enter a valid address' : undefined
      }
      case 'city': {
        return value.length < 2 ? 'Please enter a valid city' : undefined
      }
      case 'postcode': {
        return /^[0-9]{4}[A-Z]{2}$/.test(value)
          ? undefined
          : 'Please enter a valid postcode (e.g., 1234AB)'
      }
      default: {
        return undefined
      }
    }
  }

  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setForm((prev) => ({ ...prev, [name]: value }))

    if (isSubmitted) {
      const error = validateField(name as keyof DeliveryDetailsFormData, value)
      setErrors((prev) => ({
        ...prev,
        [name]: error,
      }))
    }
  }

  const handleComplete = () => {
    setIsSubmitted(true)

    // Validate only delivery fields
    const newErrors: FormErrors = {}
    let hasErrors = false

    for (const field of deliveryFields) {
      const error = validateField(field, form[field])
      if (error) {
        newErrors[field] = error
        hasErrors = true
      }
    }

    setErrors(newErrors)

    if (!hasErrors) {
      setFormData(form)
      dispatch(saveOrderAction(cartItems))
      dispatch(clearCartAction())
      navigate('/success')
    }
  }

  return (
    <div className="form">
      <Input
        label="Streetname and housenumber"
        placeholder="Some street, 13"
        name="address"
        value={form.address}
        onChange={handleChange}
        error={isSubmitted ? errors.address : undefined}
      />
      <Input
        label="Postcode"
        placeholder="AAAAXX"
        name="postcode"
        value={form.postcode}
        onChange={handleChange}
        error={isSubmitted ? errors.postcode : undefined}
      />
      <Input
        label="City"
        placeholder="Amsterdam"
        name="city"
        value={form.city}
        onChange={handleChange}
        error={isSubmitted ? errors.city : undefined}
      />
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
        }}
      >
        <Button clear onClick={onPrevious}>
          Previous
        </Button>
        <Button onClick={handleComplete}>Complete order</Button>
      </div>
    </div>
  )
}

import { useState, ChangeEvent } from 'react'
import styled, { css } from 'styled-components'

import { Button } from '../../../../components/Button'
import { Input } from '../../../../components/forms/Input'
import { Body } from '../../../../components/typography/Body'
import { type ContactDetailsFormData } from './validation'

const DisclaimerText = styled(Body)(
  ({ theme: { spacing } }) => css`
    margin-bottom: ${spacing.m};
  `
)

type ContactDetailsProps = {
  formData: ContactDetailsFormData
  setFormData: (data: Partial<ContactDetailsFormData>) => void
  onNext: () => void
}

type FormErrors = {
  [K in keyof ContactDetailsFormData]?: string
}

const contactFields: (keyof ContactDetailsFormData)[] = ['firstName', 'lastName', 'email', 'phone']

export const ContactDetails = ({ formData, setFormData, onNext }: ContactDetailsProps) => {
  const [errors, setErrors] = useState<FormErrors>({})
  const [form, setForm] = useState<ContactDetailsFormData>(formData)
  const [isSubmitted, setIsSubmitted] = useState(false)

  const validateField = (name: keyof ContactDetailsFormData, value: string): string | undefined => {
    if (!value) return 'Required'

    switch (name) {
      case 'firstName':
      case 'lastName': {
        return value.length < 2 ? 'Must be at least 2 characters' : undefined
      }
      case 'email': {
        return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)
          ? undefined
          : 'Please enter a valid email address'
      }
      case 'phone': {
        return value.length < 10 ? 'Please enter a valid phone number' : undefined
      }
      default: {
        return undefined
      }
    }
  }

  const handleChange = (e: ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target
    setForm((prev) => ({ ...prev, [name]: value }))

    if (isSubmitted) {
      const error = validateField(name as keyof ContactDetailsFormData, value)
      setErrors((prev) => ({
        ...prev,
        [name]: error,
      }))
    }
  }

  const handleNext = () => {
    setIsSubmitted(true)

    // Validate only contact fields
    const newErrors: FormErrors = {}
    let hasErrors = false

    for (const field of contactFields) {
      const error = validateField(field, form[field])
      if (error) {
        newErrors[field] = error
        hasErrors = true
      }
    }

    setErrors(newErrors)

    if (!hasErrors) {
      setFormData(form)
      onNext()
    }
  }

  return (
    <div className="form">
      <Input
        label="First name"
        placeholder="John"
        name="firstName"
        value={form.firstName}
        onChange={handleChange}
        error={isSubmitted ? errors.firstName : undefined}
      />
      <Input
        label="Last name"
        placeholder="Doe"
        name="lastName"
        value={form.lastName}
        onChange={handleChange}
        error={isSubmitted ? errors.lastName : undefined}
      />
      <Input
        label="Email"
        type="email"
        placeholder="email address"
        name="email"
        value={form.email}
        onChange={handleChange}
        error={isSubmitted ? errors.email : undefined}
      />
      <Input
        label="Phone number"
        placeholder="phone number"
        type="tel"
        name="phone"
        value={form.phone}
        onChange={handleChange}
        error={isSubmitted ? errors.phone : undefined}
      />
      <DisclaimerText size="XXS" type="span">
        We'll only use your phone to call you about your order
      </DisclaimerText>
      <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
        <Button onClick={handleNext}>Next</Button>
      </div>
    </div>
  )
}

import { useRef, useEffect } from 'react'
import * as React from 'react'
import { createPortal } from 'react-dom'

type Props = {
  selector: string
}

export const Portal: React.FC<React.PropsWithChildren<Props>> = ({ children, selector }) => {
  const ref = useRef<Element | null>(null)

  useEffect(() => {
    const element = document.querySelector<Element>(selector)
    if (element) {
      ref.current = element
    }
  }, [selector])

  return ref.current ? createPortal(children, ref.current) : null
}

import { createSlice, CaseReducer, PayloadAction } from '@reduxjs/toolkit'

import { ShopItem } from '../../types'
export interface CartItem extends ShopItem {
  quantity: number
}

export type CartState = {
  visible: boolean
  items: CartItem[]
}

const toggleVisibility: CaseReducer<CartState> = (state) => {
  state.visible = !state.visible
}

const clearCart: CaseReducer<CartState> = (state) => {
  state.visible = false
  state.items = []
}

const clearItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  state.items = state.items.filter((item) => item.id !== action.payload.id)
}

const removeItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  const existingCartItem = state.items.find((item) => item.id === action.payload.id)

  if (!existingCartItem) return

  if (existingCartItem.quantity === 1) {
    state.items = state.items.filter((item) => item.id !== action.payload.id)
  } else {
    existingCartItem.quantity -= 1
  }
}

const saveItem: CaseReducer<CartState, PayloadAction<CartItem>> = (state, action) => {
  const existingCartItem = state.items.find((item) => item.id === action.payload.id) as CartItem

  if (existingCartItem) {
    existingCartItem.quantity = action.payload.quantity
  } else {
    state.items.push(action.payload)
  }
}

const initialState: CartState = {
  visible: false,
  items: [],
}

const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    toggleVisibilityAction: toggleVisibility,
    saveItemAction: saveItem,
    clearItemAction: clearItem,
    removeItemAction: removeItem,
    clearCartAction: clearCart,
  },
})

// Extract the action creators object and the reducer
export const { actions, reducer } = cartSlice

// Extract and export each action creator by name
export const {
  toggleVisibilityAction,
  saveItemAction,
  clearItemAction,
  removeItemAction,
  clearCartAction,
} = actions

// Export the reducer, either as a default or named export
export default reducer

export const getCurrency = () => {
  return 'EUR'
}

