  }
  &.modal-enter-active {
    opacity: 1;
    transform: translateX(0);
    transition:
      opacity 120ms,
      transform 120ms;
  }
  &.modal-exit {
    opacity: 1;
  }
  &.modal-exit-active {
    opacity: 0;
    transform: scale(0.9);
    transition:
      opacity 120ms,
      transform 120ms;
  }
`

